        [Fact]
        public async Task Test_StreamWithToolCalls()
        {
            // Streaming chat completion where the assistant responds with a tool call across multiple chunks
            var baseUrl = (System.Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? string.Empty) + "/fixtures/stream_with_tool_calls";
            var client = LiterLlmLib.CreateClient("test-key", baseUrl, null, null, null);
            var chunks = new List<ChatCompletionChunk>();
            var streamContent = new System.Text.StringBuilder();
            var streamComplete = false;
            string? lastFinishReason = null;
            string? toolCallsJson = null;
            string? toolCalls0FunctionName = null;
            await foreach (var chunk in client.ChatStream(ChatCompletionRequest.FromJson("{\"messages\":[{\"content\":\"What is the weather in NYC?\",\"role\":\"user\"}],\"model\":\"gpt-4\",\"stream\":true,\"tools\":[{\"function\":{\"description\":\"Get the current weather for a given location\",\"name\":\"get_weather\",\"parameters\":{\"properties\":{\"location\":{\"description\":\"The city and state, e.g. New York, NY\",\"type\":\"string\"}},\"required\":[\"location\"],\"type\":\"object\"}},\"type\":\"function\"}]}")))
            {
                chunks.Add(chunk);
                var choice = chunk.Choices != null && chunk.Choices.Count > 0 ? chunk.Choices[0] : null;
                if (choice != null)
                {
                    var delta = choice.Delta;
                    if (delta != null && !string.IsNullOrEmpty(delta.Content))
                    {
                        streamContent.Append(delta.Content);
                    }
                    if (choice.FinishReason != null)
                    {
                        lastFinishReason = JsonNamingPolicy.SnakeCaseLower.ConvertName(choice.FinishReason.ToString()!);
                    }
                    var tcs = delta?.ToolCalls;
                    if (tcs != null && tcs.Count > 0)
                    {
                        toolCallsJson ??= JsonSerializer.Serialize(tcs.Select(tc => new { function = new { name = tc.Function?.Name } }));
                        toolCalls0FunctionName ??= tcs[0].Function?.Name;
                    }
                }
            }
            streamComplete = true;
            Assert.True(chunks.Count >= 4, "expected at least 4 chunks");
            Assert.Equal("tool_calls", lastFinishReason);
            Assert.NotNull(toolCallsJson);
            Assert.Equal("get_weather", toolCalls0FunctionName);
            Assert.True(streamComplete);
        }

